targets.expr:
sum by (type) (
  rate(
    vault_core_response_status_code{
      job=~"$job",
instance=~"$instance"


    }[$__rate_interval]
  )
)

sum by (code, type) (
  rate(
    vault_core_response_status_code{
      job=~"$job",
instance=~"$instance"


    }[$__rate_interval]
  )
)

sum(
  rate(
    vault_core_response_status_code{
      job=~"$job",
instance=~"$instance"

,
      type=~"4xx|5xx"
    }[$__rate_interval]
  )
)
/
sum(
  rate(
    vault_core_response_status_code{
      job=~"$job",
instance=~"$instance"


    }[$__rate_interval]
  )
)
* 100

sum by (type, local) (
  vault_core_mount_table_num_entries{
    job=~"$job",
instance=~"$instance"

,
cluster=~"$exported_cluster"

  }
)

sum by (type, local) (
  vault_core_mount_table_size{
    job=~"$job",
instance=~"$instance"

,
cluster=~"$exported_cluster"

  }
)

max by (peer_id) (
  vault_raft_storage_stats_commit_index{
    job=~"$job",
instance=~"$instance"

,
cluster=~"$exported_cluster"

  }
)

max by (peer_id) (
  vault_raft_storage_stats_applied_index{
    job=~"$job",
instance=~"$instance"

,
cluster=~"$exported_cluster"

  }
)

max by (peer_id) (
  vault_raft_storage_stats_fsm_pending{
    job=~"$job",
instance=~"$instance"

,
cluster=~"$exported_cluster"

  }
)

max by (peer_id) (
  vault_raft_storage_stats_term{
    job=~"$job",
instance=~"$instance"

,
cluster=~"$exported_cluster"

  }
)

sum by (database) (
  vault_raft_storage_bolt_write_count{
    job=~"$job",
instance=~"$instance"

,
cluster=~"$exported_cluster"

  }
)

sum by (database) (
  rate(
    vault_raft_storage_bolt_write_time{
      job=~"$job",
instance=~"$instance"

,
cluster=~"$exported_cluster"

    }[$__rate_interval]
  )
)

sum(
  vault_token_count_by_auth{
    job=~"$job",
instance=~"$instance"

,
cluster=~"$exported_cluster"
,
namespace=~"$exported_namespace"

  }
)

sum(
  vault_token_create_count{
    job=~"$job",
instance=~"$instance"


  }
  -
  vault_token_store_count{
    job=~"$job",
instance=~"$instance"


  }
)

sum by (auth_method) (
  vault_token_count_by_auth{
    job=~"$job",
instance=~"$instance"

,
cluster=~"$exported_cluster"
,
namespace=~"$exported_namespace"

  }
)

max(
  process_open_fds{
    job=~"$job",
instance=~"$instance"


  }
  /
  process_max_fds{
    job=~"$job",
instance=~"$instance"


  }
  * 100
)

sum(
  rate(
    process_network_receive_bytes_total{
      job=~"$job",
instance=~"$instance"


    }[$__rate_interval]
  )
)
+
sum(
  rate(
    process_network_transmit_bytes_total{
      job=~"$job",
instance=~"$instance"


    }[$__rate_interval]
  )
)
